SELECT i.*, vou.voucher_nm AS voucher_nm, ord.member_nm AS order_nm, ste.site_nm AS site_nm, cd_vis.code_label AS voucher_issue_status_cd_nm FROM pm_voucher_issue i LEFT JOIN pm_voucher vou ON vou.voucher_id = i.voucher_id LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_vis ON cd_vis.code_grp = 'VOUCHER_ISSUE_STATUS' AND cd_vis.code_value = i.voucher_issue_status_cd
ORDER BY i.voucher_issue_id ASC ORDER BY i.voucher_issue_id DESC ORDER BY i.issue_date ASC ORDER BY i.issue_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT i.*, vou.voucher_nm AS voucher_nm, ord.member_nm AS order_nm, ste.site_nm AS site_nm, cd_vis.code_label AS voucher_issue_status_cd_nm FROM pm_voucher_issue i LEFT JOIN pm_voucher vou ON vou.voucher_id = i.voucher_id LEFT JOIN od_order ord ON ord.order_id = i.order_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_vis ON cd_vis.code_grp = 'VOUCHER_ISSUE_STATUS' AND cd_vis.code_value = i.voucher_issue_status_cd
ORDER BY i.voucher_issue_id ASC ORDER BY i.voucher_issue_id DESC ORDER BY i.issue_date ASC ORDER BY i.issue_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

