UPDATE pm_voucher_issue
voucher_id = #{voucherId}, site_id = #{siteId}, member_id = #{memberId}, voucher_code = #{voucherCode}, issue_date = #{issueDate}, expire_date = #{expireDate}, use_date = #{useDate}, order_id = #{orderId}, use_amt = #{useAmt}, voucher_issue_status_cd = #{voucherIssueStatusCd}, voucher_issue_status_cd_before = #{voucherIssueStatusCdBefore}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE voucher_issue_id = #{voucherIssueId}
